import React, { useReducer, useContext, createContext, Dispatch } from 'react';
import './App.css';
import Header from './Header';
import Intro from './Intro';
import AddPlayer from './AddPlayer';
import { PhasekeeperState, PhasekeeperActions } from './Interfaces';
import PlayerList from './PlayerList';
import Phases from './Phases';
import { pbkdf2 } from 'crypto';

type ReducerRef = {
  gameState: PhasekeeperState,
  dispatch: Dispatch<any>
};

const initialGameState: PhasekeeperState = {
  players: [],
  phases: Phases
};

export const PhasekeeperContext = React.createContext<ReducerRef>({ gameState: initialGameState, dispatch: () => { } });

const App: React.FC = () => {

  const [gameState, dispatch] = useReducer((state: PhasekeeperState, action: any) => {
    switch (action.type) {

      case PhasekeeperActions.ADD_PLAYER:
        return { 
          ...state, 
          players: [
            ...state.players,
            { key: action.key, name: action.name, score: 0, currentPhase: 1 }
          ] 
        };

      case PhasekeeperActions.NEXT_PHASE:
        return {
          ...state,
          players: state.players.map(p => {
            return p.key === action.key ? { ...p, currentPhase: Math.min(Phases.length, p.currentPhase + 1) } : p;
          })
        };

      case PhasekeeperActions.INCREMENT:
        return {
          ...state,
          players: state.players.map(p => {
            return p.key === action.key ? { ...p, score: p.score += action.value } : p
          })
        };
      
      case PhasekeeperActions.REMOVE_PLAYER:
        return {
          ...state,
          players: state.players.filter(p => p.key !== action.key)
        }

      default:
        return state;
    }
  }, initialGameState);

  const reducerRef = { gameState, dispatch };

  return (
    <PhasekeeperContext.Provider value={reducerRef}>
      <div>
        <Header />
        <Intro />
        <PlayerList />
        <AddPlayer />
      </div>
    </PhasekeeperContext.Provider>
  );
}

export default App;