import React, { useContext } from 'react';
import { Player, PhasekeeperActions } from './Interfaces';
import Phases from './Phases';
import './PlayerDetail.css';
import { PhasekeeperContext } from './App';

type PlayerProps = {
    player:Player
}

export const PlayerDetail: React.FC<PlayerProps> = (props) => {
    const context = useContext(PhasekeeperContext);

    return (
        <div className="player-row" key={props.player.key }>
            <div>{props.player.name}</div>
            <div>{Phases[props.player.currentPhase - 1].goalDescription} (Phase {props.player.currentPhase})</div>
            <div>Points: {props.player.score}</div>
            <button onClick={() => context.dispatch({type: PhasekeeperActions.NEXT_PHASE, key: props.player.key})}>Next Phase</button>
            <button onClick={() => context.dispatch({type: PhasekeeperActions.INCREMENT, key: props.player.key, value: 5})}>+5</button>
            <button onClick={() => context.dispatch({type: PhasekeeperActions.INCREMENT, key: props.player.key, value: 10})}>+10</button>
            <button onClick={() => context.dispatch({type: PhasekeeperActions.INCREMENT, key: props.player.key, value: 25})}>+25</button>
            <button onClick={() => context.dispatch({type: PhasekeeperActions.INCREMENT, key: props.player.key, value: 50})}>+50</button>
            <button onClick={() => context.dispatch({type: PhasekeeperActions.REMOVE_PLAYER, key: props.player.key})}>Remove Player</button>
        </div>
    )
};

const PlayerList: React.FC = () => {

    const context = useContext(PhasekeeperContext);
    return (
        <div>
            { context.gameState.players.map(p => <PlayerDetail key={p.key} player={p} />) }
        </div>
    )
};

export default PlayerList;