import React, { useContext, useState } from 'react';
import { PhasekeeperContext } from './App';

const Intro: React.FC = () => {
  
  const context = useContext(PhasekeeperContext);

  return context.gameState.players.length ? null : (
    <div>
      Phasekeeper is used to track your phase and score in a game of <a href="https://en.wikipedia.org/wiki/Phase_10">Phase 10.</a>
      Click the + to add players and get started!
    </div>
  );

}

export default Intro;
