import React, { useReducer, useContext, DispatchWithoutAction, useState, Dispatch } from 'react';
import './AddPlayer.css';
import { PhasekeeperContext } from './App';
import { PhasekeeperActions } from './Interfaces';

const AddPlayer: React.FC = () => {

    const context = useContext(PhasekeeperContext);
    const [name, setName] = useState("New player");

    const playerCount = context.gameState.players.length;
    const key = playerCount <= 0 ? 0 : context.gameState.players[playerCount - 1].key + 1;

    return context.gameState.players.length >= 4 ? null : (

        <form className="add-player-wrapper">
            <input type="text" placeholder="New player" value={name} onChange={e => {
                setName(e.target.value)}
            }></input>
            <input type="submit" value="+" onClick={e => {
                e.preventDefault();
                context.dispatch({ type: PhasekeeperActions.ADD_PLAYER, name: name, key: key })}
            }></input>
        </form>
    );

};

export default AddPlayer;