export interface Phase {
    number: number,
    goalDescription: string
};

export interface Player {
    name: string,
    score: number,
    currentPhase: number,
    key: number
}

export type PhasekeeperState = {
    phases: Phase[],
    players: Player[]
};

export enum PhasekeeperActions {
    ADD_PLAYER = "ADD_PLAYER",
    NEXT_PHASE = "NEXT_PHASE",
    INCREMENT = "INCREMENT",
    REMOVE_PLAYER = "REMOVE_PLAYER"
};